                "prompt": "ping",
                "response": "pong",
                "weight": 0.25
            })
        )
        .unwrap();
        writeln!(
            weighted_file,
            "{}",
            serde_json::json!({
                "id": "w0",
                "prompt": "skip",
                "response": "ignored",
                "weight": 0.0
            })
